{
 "level": "A2–B1",
 "intro": "In this topic, you will learn <strong>to compare objects for equality</strong> using the <em>as…as</em> and <em>not as…as</em> constructs, which are an important alternative to the usual degrees of comparison.",
 "rules": [
 {
 "label": "AS...AS",
 "color": "emerald",
 "text": "<strong>Equality</strong> is something the same as another:",
 "example": "He is as tall as his brother."
 },
 {
 "label": "NOT AS...AS",
 "color": "rose",
 "text": "<strong>Inequality</strong> is something that is not the same as another:",
 "example": "She is not as tall as her brother."
 },
 {
 "label": "STRUCTURE",
 "color": "blue",
 "text": "Formula: <strong>as + adjective/adverb + as</strong>",
 "example": "as fast as, as beautiful as, as quickly as"
 }
 ]
}

{
 "title": "1. The main structure is as…as",
 "intro": "The <strong>as…as</strong> construct is used to express equality between two objects:",
 "rows": [
 {
 "en": "Subject + be + as + adjective + as + object",
 "ua": "Subject + be + as + adjective + as + object",
 "note": "Basic formula for adjectives"
 },
 {
 "en": "He is as tall as me.",
 "ua": "He is as tall as me.",
 "note": "✓ equality in height"
 },
 {
 "en": "This book is as interesting as that one.",
 "ua": "This book is as interesting as that one.",
 "note": "✓ equality in interest"
 },
 {
 "en": "Subject + verb + as + adverb + as + object",
 "ua": "Subject + verb + as + adverb + as + object",
 "note": "Basic formula for adverbs"
 },
 {
 "en": "She runs as fast as her sister.",
 "ua": "She runs as fast as her sister.",
 "note": "✓ equality in speed"
 },
 {
 "en": "He works as hard as anyone.",
 "ua": "He works as hard as anyone.",
 "note": "✓ equality in diligence"
 }
 ],
 "warning": "💡 Remember: between two <strong>as</strong> there is always a <strong>base form</strong> of an adjective or adverb (not comparative)."
}

{
 "title": "2. Using as…as for equality",
 "sections": [
 {
 "label": "Equality with adjectives",
 "color": "emerald",
 "description": "Use <strong>as…as</strong> to express that two things are <strong>the same</strong> in a certain way:",
 "examples": [
 {
 "en": "My car is as expensive as yours.",
 "ua": "My car is as expensive as yours."
 },
 {
 "en": "This task is as difficult as the previous one.",
 "ua": "This task is as difficult as the previous one."
 },
 {
 "en": "He is as smart as his father.",
 "ua": "He is as smart as his father."
 }
 ]
 },
 {
 "label": "Equality with adverbs",
 "color": "blue",
 "description": "Use <strong>as…as</strong> with adverbs to compare <strong>actions</strong>:",
 "examples": [
 {
 "en": "She sings as beautifully as a professional.",
 "ua": "She sings as beautifully as a professional."
 },
 {
 "en": "He speaks English as fluently as a native.",
 "ua": "He speaks English as fluently as a native."
 },
 {
 "en": "They work as efficiently as we do.",
 "ua": "They work as efficiently as we do."
 }
 ]
 },
 {
 "label": "With quantitative expressions",
 "color": "amber",
 "description": "The construction <strong>as…as</strong> can be used with <strong>much/many</strong> for quantity:",
 "examples": [
 {
 "en": "I have as much money as you.",
 "ua": "I have as much money as you."
 },
 {
 "en": "She has as many friends as her sister.",
 "ua": "She has as many friends as her sister."
 },
 {
 "en": "We need as much time as possible.",
 "ua": "We need as much time as possible."
 }
 ]
 }
 ]
}

{
 "title": "3. The structure of not as...as",
 "intro": "The construction <strong>not as…as</strong> is used to express <strong>inequality</strong> — when something is less or worse than another:",
 "rows": [
 {
 "en": "Subject + be + not as + adjective + as + object",
 "ua": "Subject + be + not as + adjective + as + object",
 "note": "Basic formula for negative comparison"
 },
 {
 "en": "He is not as tall as me.",
 "ua": "He is not as tall as me.",
 "note": "✓ it is lower"
 },
 {
 "en": "This book is not as interesting as that one.",
 "ua": "This book is not as interesting as that one.",
 "note": "✓ it is less interesting"
 },
 {
 "en": "The weather is not as cold as yesterday.",
 "ua": "The weather is not as cold as yesterday.",
 "note": "✓ it is warmer today"
 },
 {
 "en": "She doesn't run as fast as her sister.",
 "ua": "She doesn't run as fast as her sister.",
 "note": "✓ it is slower"
 }
 ],
 "warning": "💡 <strong>Not as...as</strong> = less... than. This is a mild way of saying that something is worse or less."
}

{
 "title": "4. Not as…as vs less direct forms",
 "sections": [
 {
 "label": "A gentle way of criticizing",
 "color": "rose",
 "description": "<strong>Not as…as</strong> is a <strong>polite way</strong> of saying something is worse:",
 "examples": [
 {
 "en": "It's not as good as I expected.",
 "ua": "It's not as good as I expected."
 },
 {
 "en": "It's worse than I expected.",
 "ua": "It's worse than I expected."
 },
 {
 "en": "She is not as experienced as him.",
 "ua": "She is not as experienced as him."
 }
 ]
 },
 {
 "label": "The difference is in meaning",
 "color": "blue",
 "description": "<strong>Not as…as</strong> focuses on the <strong>lack of equality</strong> rather than direct comparison:",
 "examples": [
 {
 "en": "This car is not as fast as mine.",
 "ua": "This car is not as fast as mine."
 },
 {
 "en": "This car is slower than mine.",
 "ua": "This car is slower than mine."
 },
 {
 "en": "The test wasn't as hard as I thought.",
 "ua": "The test wasn't as hard as I thought."
 }
 ]
 },
 {
 "label": "In a positive context",
 "color": "emerald",
 "description": "<strong>Not as…as</strong> can be used for <strong>pleasant surprise</strong>:",
 "examples": [
 {
 "en": "The exam wasn't as difficult as I feared.",
 "ua": "The exam wasn't as difficult as I feared."
 },
 {
 "en": "The price is not as high as expected.",
 "ua": "The price is not as high as expected."
 },
 {
 "en": "Learning English isn't as hard as people say.",
 "ua": "Learning English isn't as hard as people say."
 }
 ]
 }
 ]
}

{
 "title": "5. Common expressions with as...as",
 "intro": "There are <strong>regular expressions</strong> with the as…as construction that are worth remembering:",
 "items": [
 {
 "label": "as soon as possible",
 "title": "as soon as possible",
 "subtitle": "Please reply as soon as possible."
 },
 {
 "label": "as far as I know",
 "title": "as far as i know",
 "subtitle": "As far as I know, he's not coming."
 },
 {
 "label": "as long as",
 "title": "as long as / provided that",
 "subtitle": "You can stay as long as you want."
 },
 {
 "label": "as well as",
 "title": "as well as / as well as",
 "subtitle": "She speaks French as well as English."
 },
 {
 "label": "as much as",
 "title": "as much / just as much",
 "subtitle": "I like it as much as you do."
 },
 {
 "label": "as many as",
 "title": "as much (for counting)",
 "subtitle": "There were as many as 500 people."
 }
 ]
}

{
 "title": "6. Difference: as...as vs comparative",
 "intro": "Sometimes you can use both forms, but with <strong>different shades</strong> of meaning:",
 "rows": [
 {
 "en": "He is as tall as me.",
 "ua": "He is as tall as me.",
 "note": "= equal in height"
 },
 {
 "en": "He is taller than me.",
 "ua": "He is taller than me.",
 "note": "= he is taller"
 },
 {
 "en": "He is not as tall as me.",
 "ua": "He is not as tall as me.",
 "note": "= it is lower (softer)"
 },
 {
 "en": "He is shorter than me.",
 "ua": "He is shorter than me.",
 "note": "= he is lower (straight)"
 },
 {
 "en": "This is not as expensive as I thought.",
 "ua": "This is not as expensive as I thought.",
 "note": "= it's cheaper (indirect)"
 },
 {
 "en": "This is cheaper than I thought.",
 "ua": "This is cheaper than I thought.",
 "note": "= it's cheaper (direct)"
 }
 ],
 "warning": "💡 Use <strong>as…as</strong> for equality and mild expression of inequality, <strong>comparative</strong> for direct comparison."
}

{
 "title": "7. Common mistakes",
 "sections": [
 {
 "label": "Error 1: Incorrect form of adjective",
 "color": "rose",
 "description": "Using the <strong>comparative form</strong> instead of the basic between as…as:",
 "examples": [
 {
 "en": "❌ He is as taller as me. → ✓ He is as tall as me.",
 "ua": "❌ He is as taller as me. → ✓ He is as tall as me."
 },
 {
 "en": "❌ She is as more beautiful as her sister. → ✓ She is as beautiful as her sister.",
 "ua": "❌ She is as more beautiful as her sister. → ✓ She is as beautiful as her sister."
 },
 {
 "en": "❌ It's as better as before. → ✓ It's as good as before.",
 "ua": "❌ It's as better as before. → ✓ It's as good as before."
 }
 ]
 },
 {
 "label": "Error 2: Skipping the second \"as\"",
 "color": "amber",
 "description": "Forgetting the <strong>second as</strong> in the construction:",
 "examples": [
 {
 "en": "❌ He is as tall me. → ✓ He is as tall as me.",
 "ua": "❌ He is as tall me. → ✓ He is as tall as me."
 },
 {
 "en": "❌ She runs as fast her brother. → ✓ She runs as fast as her brother.",
 "ua": "❌ She runs as fast her brother. → ✓ She runs as fast as her brother."
 },
 {
 "en": "❌ It's as good before. → ✓ It's as good as before.",
 "ua": "❌ It's as good before. → ✓ It's as good as before."
 }
 ]
 },
 {
 "label": "Error 3: Incorrect location of not",
 "color": "sky",
 "description": "Incorrect position of <strong>not</strong> in the construction:",
 "examples": [
 {
 "en": "❌ He as not tall as me. → ✓ He is not as tall as me.",
 "ua": "❌ He as not tall as me. → ✓ He is not as tall as me."
 },
 {
 "en": "❌ She not runs as fast as him. → ✓ She doesn't run as fast as him.",
 "ua": "❌ She not runs as fast as him. → ✓ She doesn't run as fast as him."
 },
 {
 "en": "❌ It's as not good as that. → ✓ It's not as good as that.",
 "ua": "❌ It's as not good as that. → ✓ It's not as good as that."
 }
 ]
 },
 {
 "label": "Mistake 4: Confusion of than and as",
 "color": "blue",
 "description": "Using <strong>than</strong> instead of <strong>as</strong> or vice versa:",
 "examples": [
 {
 "en": "❌ He is as tall than me. → ✓ He is as tall as me / taller than me.",
 "ua": "❌ He is as tall than me. → ✓ He is as tall as me / taller than me."
 },
 {
 "en": "❌ She is not as fast than him. → ✓ She is not as fast as him.",
 "ua": "❌ She is not as fast than him. → ✓ She is not as fast as him."
 },
 {
 "en": "❌ It's better as before. → ✓ It's better than before.",
 "ua": "❌ It's better as before. → ✓ It's better than before."
 }
 ]
 }
 ]
}

{
 "title": "8. Extended designs",
 "sections": [
 {
 "label": "With twice / three times",
 "color": "emerald",
 "description": "You can add <strong>multipliers</strong> before as…as:",
 "examples": [
 {
 "en": "He is twice as tall as his brother.",
 "ua": "He is twice as tall as his brother."
 },
 {
 "en": "This costs three times as much as that.",
 "ua": "This costs three times as much as that."
 },
 {
 "en": "She earns half as much as him.",
 "ua": "She earns half as much as him."
 }
 ]
 },
 {
 "label": "With nearly / almost / quite",
 "color": "blue",
 "description": "You can use <strong>amplifiers</strong> before the first as:",
 "examples": [
 {
 "en": "He is nearly as tall as me.",
 "ua": "He is nearly as tall as me."
 },
 {
 "en": "She runs almost as fast as him.",
 "ua": "She runs almost as fast as him."
 },
 {
 "en": "It's quite as good as the original.",
 "ua": "It's quite as good as the original."
 }
 ]
 },
 {
 "label": "In the questions",
 "color": "amber",
 "description": "Construction <strong>as…as</strong> in interrogative sentences:",
 "examples": [
 {
 "en": "Is he as tall as you?",
 "ua": "Is he as tall as you?"
 },
 {
 "en": "Does she work as hard as her colleagues?",
 "ua": "Does she work as hard as her colleagues?"
 },
 {
 "en": "Isn't this as expensive as that one?",
 "ua": "Isn't this as expensive as that one?"
 }
 ]
 }
 ]
}

{
 "title": "9. Quick checklist",
 "items": [
 {
 "label": "Check 1",
 "color": "emerald",
 "title": "Are both \"as\"?",
 "wrong": "He is as tall me.",
 "right": "→ He is as tall <strong>as</strong> me."
 },
 {
 "label": "Check 2",
 "color": "blue",
 "title": "Is the base form of the adjective?",
 "wrong": "She is as taller as him.",
 "right": "→ She is as <strong>tall</strong> as him."
 },
 {
 "label": "Check 3",
 "color": "rose",
 "title": "Is \"not\" correct?",
 "wrong": "He as not tall as me.",
 "right": "→ He is <strong>not</strong> as tall as me."
 },
 {
 "label": "Check 4",
 "color": "amber",
 "title": "Are you confusing as with than?",
 "wrong": "She is as tall than me.",
 "right": "→ She is as tall <strong>as</strong> me."
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Degrees of Comparison",
 "url": "/theory/adjectives/theory-degrees-of-comparison"
 },
 {
 "label": "Comparative vs Superlative",
 "url": "/theory/adjectives/comparative-vs-superlative"
 },
 {
 "label": "Adjectives vs Adverbs",
 "url": "/theory/adjectives/adjectives-vs-adverbs"
 }
 ]
}
